import React, { useEffect, useState } from "react";
import { Box, Typography, Paper } from "@mui/material";
import { initializeApp } from "https://www.gstatic.com/firebasejs/10.11.1/firebase-app.js";
import {
  getDatabase,
  ref,
  onValue,
} from "https://www.gstatic.com/firebasejs/10.11.1/firebase-database.js";
import { db } from "./firebase";

const Dashboard = () => {
  const [data, setData] = useState({});

  useEffect(() => {
    const usersRef = ref(db, "users");

    onValue(usersRef, (snapshot) => {
      const val = snapshot.val();
      if (val) {
        setData(val);
      }
    });
  }, []);

  return (
    <Box p={3}>
      <Typography variant="h4" mb={3}>
        Dashboard
      </Typography>

      {Object.entries(data).map(([userId, answers]) => (
        <Paper key={userId} sx={{ p: 2, mb: 3 }}>
          <Typography variant="h6" mb={2}>
            Kullanıcı: {userId}
          </Typography>

          {Object.entries(answers).map(([questionKey, answer]) => (
            <Box
              key={questionKey}
              sx={{
                mb: 1,
                p: 1,
                borderBottom: "1px solid #ccc",
              }}
            >
              <Typography variant="subtitle2">Soru: {questionKey}</Typography>

              <Typography variant="body1">Cevap: {answer}</Typography>
            </Box>
          ))}
        </Paper>
      ))}
    </Box>
  );
};

export default Dashboard;
