import React, { useState } from "react";
import { Box, useMediaQuery } from "@mui/material";
import ImageList from "@mui/material/ImageList";
import ImageListItem from "@mui/material/ImageListItem";
import ImageListItemBar from "@mui/material/ImageListItemBar";
import IconButton from "@mui/material/IconButton";
import Button from "@mui/material/Button";
import InfoIcon from "@mui/icons-material/Info";
import Modal from "@mui/material/Modal";
import Typography from "@mui/material/Typography";

const style = {
  position: "absolute",
  top: "50%",
  left: "50%",
  transform: "translate(-50%, -50%)",
  width: 400,
  bgcolor: "background.paper",
  border: "2px solid #000",
  boxShadow: 24,
  p: 4,
};

const Question = ({ question, onClick }) => {
  const [title, setTitle] = useState(null);
  const [description, setDescription] = useState(null);
  const [open, setOpen] = useState(false);

  const handleOpen = () => setOpen(true);
  const handleClose = () => setOpen(false);
  const isMobile = useMediaQuery("(max-width:600px)");

  function scrollToTop() {
    const scrollableDiv = document.getElementById("scrollableDiv");
    if (scrollableDiv) scrollableDiv.scrollTop = 0;
  }

  if (!question) return null;

  return (
    <Box sx={{ width: "100%" }} p={3}>
      <Typography variant="h5" mb={2}>
        {question.title}
      </Typography>

      <Box sx={{ overflow: "scroll" }}>
        <ImageList
          id="scrollableDiv"
          sx={{ width: "100%", height: "calc(100vh - 148px)" }}
          cols={
            isMobile &&
            (question.title === "AXA Sigorta Yılın Takımı" ||
              question.title === "Yılın Paralimpik - Engelli Sporcusu/Takımı")
              ? 1
              : isMobile
                ? 2
                : question.title === "AXA Sigorta Yılın Takımı" ||
                    question.title ===
                      "Yılın Paralimpik - Engelli Sporcusu/Takımı"
                  ? 3
                  : 6
          }
          style={{ gap: "24px" }}
        >
          {question.options.map((item) => (
            <Box key={item.img}>
              <ImageListItem>
                {/* 🔥 SABİT BOYUTLU IMAGE */}
                <Box
                  sx={{
                    width: "100%",
                    aspectRatio: isMobile ? "1 / 0.76" : "1 / 1",
                    overflow: "hidden",
                    // borderRadius: "8px",
                    "&:hover img": {
                      transform: "scale(1.05)",
                    },
                  }}
                >
                  <img
                    src={item.img}
                    alt={item.title}
                    loading="lazy"
                    style={{
                      width: "100%",
                      height: "100%",
                      objectFit: "cover",
                      transition: "0.3s",
                    }}
                  />
                </Box>

                <ImageListItemBar
                  title={item.title}
                  subtitle={item.author}
                  sx={{
                    "& .MuiImageListItemBar-title": { whiteSpace: "pre-wrap" },
                  }}
                  actionIcon={
                    <IconButton
                      sx={{ color: "rgba(255, 255, 255, 0.54)" }}
                      onClick={() => {
                        setTitle(item.title);
                        setDescription(item?.description);
                        handleOpen();
                      }}
                    >
                      <InfoIcon />
                    </IconButton>
                  }
                />
              </ImageListItem>

              <Button
                variant="contained"
                fullWidth
                sx={{ borderRadius: 0 }}
                onClick={() => {
                  scrollToTop();
                  onClick(item, question);
                }}
              >
                Oy Ver
              </Button>
            </Box>
          ))}
        </ImageList>
      </Box>

      <Modal open={open} onClose={handleClose}>
        <Box sx={style}>
          <Typography variant="h6">{title}</Typography>
          <Typography sx={{ mt: 2 }}>{description}</Typography>
        </Box>
      </Modal>
    </Box>
  );
};

export default Question;
